import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"桌式推进式火箭弹","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/桌式推进式火箭弹.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/桌式推进式火箭弹.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/桌式推进式火箭弹.md"};function p(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"桌式推进式火箭弹",tabindex:"-1"},[s("桌式推进式火箭弹 "),e("a",{class:"header-anchor",href:"#桌式推进式火箭弹","aria-label":'Permalink to "桌式推进式火箭弹"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="桌式推进式火箭弹-1" tabindex="-1">桌式推进式火箭弹 <a class="header-anchor" href="#桌式推进式火箭弹-1" aria-label="Permalink to &quot;桌式推进式火箭弹&quot;">​</a></h1><p>桌式推进式火箭弹<br> 价格：D+500<br> 固定伤害：9L<br> 弹容量：1<br> 射程：45m<br> 伤害类型：物理-穿刺</p><p>介绍：<br> “请问TRPG的全名（八个字）是？”<br> “桌面推进式火箭弹！”<br> “？”#无情打回<br> “不对吗？那就是桌式推进式火箭弹！”<br> “你再看看我们的群名呢！”#愤怒的打回</p><p>话虽如此，倘若战场上真的有一张桌子朝你飞来，甚至还有火箭弹的尾迹，那确实足够震撼的。<br> 所以我们的工匠真的做出了这种桌子！至于它怎么通过海关的你不要想，你只需要知道这玩意平时是普通的木头桌子，四四方方的看起来人畜无害，但是被一脚踢倒后踹一下就能变成推进式火箭弹飞出去就可以了！</p><p>【我真的只是桌子！】话虽如此，你在战场上突然拿出一张桌子还是可疑的很。所以任何看到你拿出这张桌子的人都可以进行一个DC为6的智力检定，成功则一眼丁真察觉出你的桌子定有蹊跷，失败则你对其发起的第一次攻击视为具有C级先制的效果。另外，它确实能干一个桌子能干的事情，但不妨碍每个人都可以对其进行一次检定，以确认对方能不能看出这张桌子的蹊跷。</p><p>【哈哈，骗到你啦！】使用桌式推进式火箭弹之前，你必须一脚踹倒已经在你面前的“桌式推进式火箭弹”，或者把你手里的“桌式推进式火箭弹”侧放面朝敌人，这需要消耗你一个移动动作。另外，其只能对单一目标造成伤害，且目标使用反射豁免固定伤害而非正常防御。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
